def is_ip_private(ip_str: str) -> bool:
    """Check if an IP address falls within private/reserved ranges."""
    try:
        ip = ipaddress.ip_address(ip_str)
        for network in PRIVATE_IP_NETWORKS:
            if ip in network:
                return True
        return False
    except ValueError:
        # If we can't parse it, block it
        return True


def is_hostname_blocked(hostname: str) -> bool:
    """Check if a hostname is in the blocklist."""
    hostname_lower = hostname.lower().strip(".")

    # Check exact matches
    if hostname_lower in BLOCKED_HOSTNAMES:
        return True

    # Check patterns
    for pattern in BLOCKED_HOSTNAME_PATTERNS:
        if pattern.match(hostname_lower):
            return True

    # Check blocked TLDs
    parts = hostname_lower.split(".")
    if parts and parts[-1] in BLOCKED_TLDS:
        return True

    return False


def resolve_and_validate_host(hostname: str) -> Tuple[bool, str, list]:
    """
    Resolve hostname to IP addresses and validate none are private.
    Returns (is_safe, reason, ip_addresses).
    """
    if is_hostname_blocked(hostname):
        return False, f"Hostname '{hostname}' is blocked", []

    # Check if hostname is already an IP address
    try:
        ip = ipaddress.ip_address(hostname)
        if is_ip_private(str(ip)):
            return False, f"IP address {hostname} is in a private/reserved range", []
        return True, "OK", [str(ip)]
    except ValueError:
        pass  # Not an IP, proceed with DNS resolution

    try:
        # Resolve all addresses
        addr_infos = socket.getaddrinfo(hostname, None, socket.AF_UNSPEC, socket.SOCK_STREAM)
        if not addr_infos:
            return False, f"Could not resolve hostname '{hostname}'", []

        ip_addresses = list(set(info[4][0] for info in addr_infos))

        # Check ALL resolved IPs - if any are private, block
        for ip_str in ip_addresses:
            if is_ip_private(ip_str):
                return False, f"Hostname '{hostname}' resolves to private/reserved IP {ip_str}", []

        return True, "OK", ip_addresses

    except socket.gaierror as e:
        return False, f"DNS resolution failed for '{hostname}': {e}", []


def validate_url(url: str) -> Tuple[bool, str, str]:
    """
    Validate and sanitize a URL.
    Returns (is_valid, reason, sanitized_url).
    """
    if not url or not isinstance(url, str):
        return False, "URL is required and must be a string", ""

    url = url.strip()

    # Length check
    if len(url) > 2048:
        return False, "URL exceeds maximum length of 2048 characters", ""

    # Parse URL
    try:
        parsed = urllib.parse.urlparse(url)
    except Exception:
        return False, "Failed to parse URL", ""

    # Validate scheme
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        return False, f"URL scheme '{parsed.scheme}' is not allowed. Only {ALLOWED_SCHEMES} are permitted", ""

    # Must have a hostname
    hostname = parsed.hostname
    if not hostname:
        return False, "URL must contain a valid hostname", ""

    # Validate port if specified
    port = parsed.port
    if port is not None:
        # Only allow standard web ports
        allowed_ports = {80, 443, 8080, 8443}
        if port not in allowed_ports:
            return False, f"Port {port} is not allowed. Allowed ports: {allowed_ports}", ""

    # Block URLs with credentials
    if parsed.username or parsed.password:
        return False, "URLs with embedded credentials are not allowed", ""

    # Block URLs with suspicious characters that could be used for SSRF bypass
    # Check for URL encoding tricks
    if "\\" in url or "\t" in url or "\n" in url or "\r" in url:
        return False, "URL contains invalid characters", ""

    # Check for Unicode/IDN homograph attacks - only allow ASCII hostnames
    try:
        hostname.encode("ascii")
    except UnicodeEncodeError:
        # Convert to punycode for IDN support but log it
        try:
            hostname = hostname.encode("idna").decode("ascii")
            logger.warning(f"IDN hostname detected, converted to punycode: {hostname}")
        except (UnicodeError, UnicodeDecodeError):
            return False, "Invalid internationalized domain name", ""

    # Resolve and validate the host
    is_safe, reason, _ = resolve_and_validate_host(hostname)
    if not is_safe:
        return False, reason, ""

    # Reconstruct sanitized URL
    sanitized = urllib.parse.urlunparse((
        parsed.scheme.lower(),
        parsed.netloc,
        parsed.path or "/",
        parsed.params,
        parsed.query,
        ""  # Strip fragment as it's client-side only
    ))

    return True, "OK", sanitized


def validate_redirect_url(url: str, original_hostname: str) -> Tuple[bool, str]:
    """
    Validate a redirect destination URL with additional checks.
    """
    is_valid, reason, sanitized = validate_url(url)
    if not is_valid:
        return False, f"Redirect blocked: {reason}"

    parsed = urllib.parse.urlparse(url)
    redirect_hostname = parsed.hostname

    # Re-resolve at redirect time to prevent DNS rebinding / TOCTOU
    is_safe, reason, _ = resolve_and_validate_host(redirect_hostname)
    if not is_safe:
        return False, f"Redirect blocked (re-validation): {reason}"

    return True, "OK"


def follow_redirects_safely(url: str, max_redirects: int = MAX_REDIRECTS) -> Tuple[bool, str, str]:
    """
    Follow redirects manually with validation at each step.
    Returns (success, reason, final_url).
    """
    current_url = url
    original_parsed = urllib.parse.urlparse(url)
    visited_urls = set()

    for i in range(max_redirects + 1):
        if current_url in visited_urls:
            return False, "Redirect loop detected", current_url
        visited_urls.add(current_url)

        try:
            # Make request without following redirects
            response = requests.head(
                current_url,
                allow_redirects=False,
                timeout=REQUEST_TIMEOUT,
                headers={
                    "User-Agent": "ScreenshotService/1.0 (Link Preview Bot)",
                    "Accept": "text/html",
                },
                verify=True,  # Enforce SSL verification
            )

            if response.status_code in (301, 302, 303, 307, 308):
                if i >= max_redirects:
                    return False, f"Too many redirects (max {max_redirects})", current_url

                redirect_url = response.headers.get("Location", "")
                if not redirect_url:
                    return False, "Redirect with no Location header", current_url

                # Handle relative redirects
                redirect_url = urllib.parse.urljoin(current_url, redirect_url)

                # Validate the redirect destination
                is_valid, reason = validate_redirect_url(redirect_url, original_parsed.hostname)
                if not is_valid:
                    return False, reason, current_url

                logger.info(f"Following redirect {i + 1}: {current_url} -> {redirect_url}")
                current_url = redirect_url
                continue

            # Not a redirect, we're done
            return True, "OK", current_url

        except requests.exceptions.SSLError:
            return False, "SSL certificate verification failed", current_url
        except requests.exceptions.ConnectionError as e:
            return False, f"Connection error: {e}", current_url
        except requests.exceptions.Timeout:
            return False, "Request timed out during redirect following", current_url
        except requests.exceptions.RequestException as e:
            return False, f"Request error: {e}", current_url

    return False, "Redirect following did not complete", current_url


def create_chrome_driver():
    """Create a headless Chrome WebDriver with security hardening."""
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--disable-extensions")
    chrome_options.add_argument("--disable-plugins")
    chrome_options.add_argument(f"--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}")

    # Security hardening
    chrome_options.add_argument("--disable-web-security=false")
    chrome_options.add_argument("--disable-features=NetworkService")
    chrome_options.add_argument("--disable-background-networking")
    chrome_options.add_argument("--disable-default-apps")
    chrome_options.add_argument("--disable-sync")
    chrome_options.add_argument("--disable-translate")
    chrome_options.add_argument("--disable-background-timer-throttling")
    chrome_options.add_argument("--no-first-run")
    chrome_options.add_argument("--safebrowsing-disable-auto-update")
    chrome_options.add_argument("--disable-popup-blocking")

    # Disable file access
    chrome_options.add_argument("--disable-file-system")
    chrome_options.add_argument("--allow-file-access-from-files=false")

    # Block access to local resources via Chrome
    chrome_options.add_argument("--host-resolver-rules=MAP metadata.google.internal 0.0.0.0, MAP 169.254.169.254 0.0.0.0, MAP localhost 0.0.0.0")

    # Disable JavaScript features that could be abused
    chrome_options.add_argument("--disable-notifications")
    chrome_options.add_argument("--disable-geolocation")
    chrome_options.add_argument("--disable-media-stream")

    # Set user agent
    chrome_options.add_argument("--user-agent=ScreenshotService/1.0 (Link Preview Bot)")

    if CHROME_BINARY_PATH:
        chrome_options.binary_location = CHROME_BINARY_PATH

    service = Service(executable_path=CHROME_DRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(SCREENSHOT_TIMEOUT)
    driver.set_script_timeout(SCREENSHOT_TIMEOUT)

    return driver


def take_screenshot(url: str) -> bytes:
    """Take a screenshot of the given URL using headless Chrome."""
    driver = None
    try:
        driver = create_chrome_driver()
        driver.get(url)

        # Wait for page to load
        time.sleep(2)

        # Take screenshot
        screenshot_png = driver.get_screenshot_as_png()
        return screenshot_png

    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass


def create_thumbnail(screenshot_bytes: bytes) -> bytes:
    """Create a thumbnail from the screenshot."""
    image = Image.open(io.BytesIO(screenshot_bytes))

    # Create thumbnail maintaining aspect ratio
    image.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.Resampling.LANCZOS)

    # Save as JPEG for smaller file size
    output = io.BytesIO()
    # Convert to RGB if necessary (PNG might have alpha channel)
    if image.mode in ("RGBA", "P"):
        image = image.convert("RGB")
    image.save(output, format="JPEG", quality=85, optimize=True)
    output.seek(0)

    return output.read()


def upload_to_s3(image_bytes: bytes, url: str) -> str:
    """Upload the thumbnail to S3 and return the public URL."""
    s3_client = boto3.client("s3", region_name=S3_REGION)

    # Generate a deterministic key based on URL for caching
    url_hash = hashlib.sha256(url.encode("utf-8")).hexdigest()
    unique_id = uuid.uuid4().hex[:8]
    key = f"thumbnails/{url_hash[:2]}/{url_hash[2:4]}/{url_hash}_{unique_id}.jpg"

    s3_client.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=image_bytes,
        ContentType="image/jpeg",
        CacheControl="public, max-age=86400",  # Cache for 24 hours
        Metadata={
            "source-url": url[:256],  # Truncate for metadata limits
        },
    )

    # Generate the S3 URL
    s3_url = f"https://{S3_BUCKET}.s3.{S3_REGION}.amazonaws.com/{key}"
    return s3_url


def check_existing_screenshot(url: str) -> Optional[str]:
    """Check if a recent screenshot already exists in S3."""
    s3_client = boto3.client("s3", region_name=S3_REGION)
    url_hash = hashlib.sha256(url.encode("utf-8")).hexdigest()
    prefix = f"thumbnails/{url_hash[:2]}/{url_hash[2:4]}/{url_hash}_"

    try:
        response = s3_client.list_objects_v2(
            Bucket=S3_BUCKET,
            Prefix=prefix,
            MaxKeys=1,
        )

        if response.get("Contents"):
            obj = response["Contents"][0]
            # Check if the screenshot is less than 24 hours old
            from datetime import datetime, timezone, timedelta
            age = datetime.now(timezone.utc) - obj["LastModified"]
            if age < timedelta(hours=24):
                return f"https://{S3_BUCKET}.s3.{S3_REGION}.amazonaws.com/{obj['Key']}"

    except Exception as e:
        logger.warning(f"Error checking existing screenshot: {e}")

    return None


def require_api_key(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if API_KEY:
            provided_key = request.headers.get("X-API-Key", "")
            if provided_key != API_KEY:
                return jsonify({"error": "Invalid or missing API key"}), 401
        return f(*args, **kwargs)
    return decorated_function


# Rate limiting (simple in-memory, use Redis in production)
from collections import defaultdict
import threading

rate_limit_lock = threading.Lock()
rate_limit_store = defaultdict(list)
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 10  # per window


def check_rate_limit(client_ip: str) -> bool:
    """Check if the client has exceeded the rate limit."""
    now = time.time()
    with rate_limit_lock:
        # Clean old entries
        rate_limit_store[client_ip] = [
            t for t in rate_limit_store[client_ip]
            if now - t < RATE_LIMIT_WINDOW
        ]
        if len(rate_limit_store[client_ip]) >= RATE_LIMIT_MAX_REQUESTS:
            return False
        rate_limit_store[client_ip].append(now)
        return True


