@app.route("/screenshot", methods=["POST"])
@require_api_key
def screenshot():
    """
    Take a screenshot of a URL and return a thumbnail.

    Request body:
    {
        "url": "https://example.com",
        "force_refresh": false
    }
    """
    # Rate limiting
    client_ip = request.remote_addr
    if not check_rate_limit(client_ip):
        return jsonify({
            "error": "Rate limit exceeded. Please try again later.",
        }), 429

    # Parse request
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    url = data.get("url", "").strip()
    force_refresh = data.get("force_refresh", False)

    if not url:
        return jsonify({"error": "URL is required"}), 400

    # Step 1: Validate the URL
    logger.info(f"Validating URL: {url}")
    is_valid, reason, sanitized_url = validate_url(url)
    if not is_valid:
        logger.warning(f"URL validation failed for '{url}': {reason}")
        return jsonify({"error": f"Invalid URL: {reason}"}), 400

    # Step 2: Check for cached screenshot
    if not force_refresh:
        existing_url = check_existing_screenshot(sanitized_url)
        if existing_url:
            logger.info(f"Returning cached screenshot for: {sanitized_url}")
            return jsonify({
                "url": sanitized_url,
                "thumbnail_url": existing_url,
                "cached": True,
            }), 200

    # Step 3: Follow redirects safely and validate each hop
    logger.info(f"Following redirects for: {sanitized_url}")
    redirect_ok, redirect_reason, final_url = follow_redirects_safely(sanitized_url)
    if not redirect_ok:
        logger.warning(f"Redirect validation failed for '{sanitized_url}': {redirect_reason}")
        return jsonify({"error": f"URL validation failed: {redirect_reason}"}), 400

    # Step 4: Re-validate the final URL after redirects (defense in depth against DNS rebinding)
    is_valid, reason, final_sanitized = validate_url(final_url)
    if not is_valid:
        logger.warning(f"Final URL validation failed for '{final_url}': {reason}")
        return jsonify({"error": f"Final URL validation failed: {reason}"}), 400

    # Step 5: Take the screenshot
    logger.info(f"Taking screenshot of: {final_sanitized}")
    try:
        screenshot_bytes = take_screenshot(final_sanitized)
    except Exception as e:
        logger.error(f"Screenshot failed for '{final_sanitized}': {e}")
        return jsonify({"error": "Failed to capture screenshot"}), 500

    # Step 6: Create thumbnail
    try:
        thumbnail_bytes = create_thumbnail(screenshot_bytes)
    except Exception as e:
        logger.error(f"Thumbnail creation failed: {e}")
        return jsonify({"error": "Failed to create thumbnail"}), 500

    # Step 7: Upload to S3
    try:
        thumbnail_url = upload_to_s3(thumbnail_bytes, sanitized_url)
    except Exception as e:
        logger.error(f"S3 upload failed: {e}")
        return jsonify({"error": "Failed to store screenshot"}), 500

    logger.info(f"Screenshot completed for: {sanitized_url} -> {thumbnail_url}")

    return jsonify({
        "url": sanitized_url,
        "final_url": final_sanitized,
        "thumbnail_url": thumbnail_url,
        "cached": False,
    }), 200


@app.route("/validate", methods=["POST"])
@require_api_key
def validate():
    """
    Validate a URL without taking a screenshot.
    Useful for pre-validation in the frontend.
    """
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    url = data.get("url", "").strip()
    if not url:
        return jsonify({"error": "URL is required"}), 400

    is_valid, reason, sanitized_url = validate_url(url)

    return jsonify({
        "url": url,
        "sanitized_url": sanitized_url if is_valid else None,
        "is_valid": is_valid,
        "reason": reason,
    }), 200 if is_valid else 400


